        let storedHash = UserDefaults.standard.string(forKey: "app_hash")
        
        if storedHash == nil {
            UserDefaults.standard.set(hash, forKey: "app_hash")
            return true
        }
        
        return hash == storedHash
    }
    
    private func isReverseEngineeringDetected() -> Bool {
