// MARK: - Cryptography Helper
class CryptoHelper {
    static func generateRandomBytes(count: Int) -> Data? {
        var bytes = [UInt8](repeating: 0, count: count)
        let status = SecRandomCopyBytes(kSecRandomDefault, count, &bytes)
        
        if status == errSecSuccess {
            return Data(bytes)
        }
        return nil
    }
    
    static func sha256(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func doubleSha256(_ data: Data) -> Data {
        return sha256(sha256(data))
    }
    
    static func ripemd160(_ data: Data) -> Data {
        var hash = [UInt8](repeating: 0, count: Int(CC_RIPEMD160_DIGEST_LENGTH))
        data.withUnsafeBytes {
            _ = CC_RIPEMD160($0.baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash)
    }
    
    static func encryptAES256(data: Data, key: Data, iv: Data) -> Data? {
        let cryptLength = data.count + kCCBlockSizeAES128
        var cryptData = Data(count: cryptLength)
        
        var numBytesEncrypted: size_t = 0
        
        let cryptStatus = cryptData.withUnsafeMutableBytes { cryptBytes in
            data.withUnsafeBytes { dataBytes in
                key.withUnsafeBytes { keyBytes in
                    iv.withUnsafeBytes { ivBytes in
                        CCCrypt(
                            CCOperation(kCCEncrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress, key.count,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress, data.count,
                            cryptBytes.baseAddress, cryptLength,
                            &numBytesEncrypted
                        )
                    }
                }
            }
        }
        
        if cryptStatus == kCCSuccess {
            cryptData.removeSubrange(numBytesEncrypted..<cryptData.count)
            return cryptData
        }
        
        return nil
    }
    
    static func decryptAES256(data: Data, key: Data, iv: Data) -> Data? {
        let cryptLength = data.count + kCCBlockSizeAES128
        var cryptData = Data(count: cryptLength)
        
        var numBytesDecrypted: size_t = 0
        
        let cryptStatus = cryptData.withUnsafeMutableBytes { cryptBytes in
            data.withUnsafeBytes { dataBytes in
                key.withUnsafeBytes { keyBytes in
                    iv.withUnsafeBytes { ivBytes in
                        CCCrypt(
                            CCOperation(kCCDecrypt),
                            CCAlgorithm(kCCAlgorithmAES),
                            CCOptions(kCCOptionPKCS7Padding),
                            keyBytes.baseAddress, key.count,
                            ivBytes.baseAddress,
                            dataBytes.baseAddress, data.count,
                            cryptBytes.baseAddress, cryptLength,
                            &numBytesDecrypted
                        )
                    }
                }
            }
        }
        
        if cryptStatus == kCCSuccess {
            cryptData.removeSubrange(numBytesDecrypted..<cryptData.count)
            return cryptData
        }
        
        return nil
    }
}

// MARK: - Secp256k1 Implementation
class Secp256k1 {
    private static let curveOrder = Data(hex: "FFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEBAAEDCE6AF48A03BBFD25E8CD0364141")!
    
    static func generatePrivateKey() -> Data? {
        guard let randomBytes = CryptoHelper.generateRandomBytes(count: 32) else {
            return nil
        }
        
        let privateKeyInt = BigInt(data: randomBytes)
        let orderInt = BigInt(data: curveOrder)
        
        if privateKeyInt >= orderInt || privateKeyInt == BigInt(0) {
            return generatePrivateKey()
        }
        
        return randomBytes
    }
    
    static func getPublicKey(privateKey: Data) -> Data? {
        // Simplified public key derivation
        // In production, use a proper secp256k1 library
        let hash = CryptoHelper.sha256(privateKey)
        var publicKey = Data([0x04])
        publicKey.append(hash)
        publicKey.append(CryptoHelper.sha256(hash))
        return publicKey
    }
    
    static func sign(message: Data, privateKey: Data) -> Data? {
        let messageHash = CryptoHelper.sha256(message)
        
        // Simplified ECDSA signing
        // In production, use a proper secp256k1 library
        var signature = Data()
        signature.append(CryptoHelper.sha256(privateKey + messageHash))
        signature.append(CryptoHelper.sha256(messageHash + privateKey))
        
        return signature
    }
}

// MARK: - BigInt Helper
struct BigInt {
    let data: Data
    
    init(_ value: Int) {
        var val = value
        self.data = Data(bytes: &val, count: MemoryLayout<Int>.size)
    }
    
    init(data: Data) {
        self.data = data
    }
    
    static func >=(lhs: BigInt, rhs: BigInt) -> Bool {
        return lhs.data.lexicographicallyPrecedes(rhs.data) == false
    }
    
    static func ==(lhs: BigInt, rhs: BigInt) -> Bool {
        return lhs.data == rhs.data
    }
}

// MARK: - Wallet
class Wallet {
    let privateKey: Data
    let publicKey: Data
    let address: String
    
    init?(privateKey: Data) {
        self.privateKey = privateKey
        
        guard let pubKey = Secp256k1.getPublicKey(privateKey: privateKey) else {
            return nil
        }
        self.publicKey = pubKey
        
        let pubKeyHash = CryptoHelper.ripemd160(CryptoHelper.sha256(pubKey))
        var addressData = Data([0x00])
        addressData.append(pubKeyHash)
        
        let checksum = CryptoHelper.doubleSha256(addressData).prefix(4)
        addressData.append(checksum)
        
        self.address = addressData.base58Encoded()
    }
    
    static func generate() -> Wallet? {
        guard let privateKey = Secp256k1.generatePrivateKey() else {
            return nil
        }
        return Wallet(privateKey: privateKey)
    }
    
    func sign(transaction: Transaction) -> Data? {
        let txData = transaction.serialize()
        return Secp256k1.sign(message: txData, privateKey: privateKey)
    }
}

// MARK: - Transaction
struct Transaction {
    let from: String
    let to: String
    let amount: Decimal
    let fee: Decimal
    let nonce: Int
    var signature: Data?
    
    func serialize() -> Data {
        var data = Data()
        data.append(from.data(using: .utf8)!)
        data.append(to.data(using: .utf8)!)
        data.append(String(describing: amount).data(using: .utf8)!)
        data.append(String(describing: fee).data(using: .utf8)!)
        data.append(withUnsafeBytes(of: nonce) { Data($0) })
        return data
    }
    
    func toJSON() -> [String: Any] {
        var json: [String: Any] = [
            "from": from,
            "to": to,
            "amount": String(describing: amount),
            "fee": String(describing: fee),
            "nonce": nonce
        ]
        
        if let sig = signature {
            json["signature"] = sig.hexEncodedString()
        }
        
        return json
    }
}

// MARK: - Blockchain Communication
class BlockchainAPI {
    static let shared = BlockchainAPI()
    private let baseURL = "https://api.blockchain.example.com"
    
    private init() {}
    
    func getBalance(address: String, completion: @escaping (Result<Decimal, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/balance/\(address)") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let balanceString = json["balance"] as? String,
                  let balance = Decimal(string: balanceString) else {
                completion(.failure(NSError(domain: "Invalid response", code: -1)))
                return
            }
            
            completion(.success(balance))
        }.resume()
    }
    
    func sendTransaction(_ transaction: Transaction, completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/transaction") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let jsonData = try? JSONSerialization.data(withJSONObject: transaction.toJSON())
        request.httpBody = jsonData
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let txHash = json["transaction_hash"] as? String else {
                completion(.failure(NSError(domain: "Invalid response", code: -1)))
                return
            }
            
            completion(.success(txHash))
        }.resume()
    }
    
    func getTransactionHistory(address: String, completion: @escaping (Result<[[String: Any]], Error>) -> Void) {
        guard let url = URL(string: "\(baseURL)/transactions/\(address)") else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1)))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data,
                  let json = try? JSONSerialization.jsonObject(with: data) as? [String: Any],
                  let transactions = json["transactions"] as? [[String: Any]] else {
                completion(.failure(NSError(domain: "Invalid response", code: -1)))
                return
            }
            
            completion(.success(transactions))
        }.resume()
    }
}

// MARK: - Wallet Manager
class WalletManager {
    static let shared = WalletManager()
    private var currentWallet: Wallet?
    private let walletIdentifier = "com.cryptowallet.privatekey"
    
    private init() {}
    
    func createWallet(completion: @escaping (Result<Wallet, Error>) -> Void) {
        BiometricAuthManager.shared.authenticate(reason: "Create new wallet") { success, error in
            if !success {
                completion(.failure(error ?? NSError(domain: "Authentication failed", code: -1)))
                return
            }
            
            guard let wallet = Wallet.generate() else {
                completion(.failure(NSError(domain: "Failed to generate wallet", code: -1)))
                return
            }
            
            if SecureStorage.shared.savePrivateKey(wallet.privateKey, identifier: self.walletIdentifier) {
                self.currentWallet = wallet
                completion(.success(wallet))
            } else {
                completion(.failure(NSError(domain: "Failed to save wallet", code: -1)))
            }
        }
    }
    
    func loadWallet(completion: @escaping (Result<Wallet, Error>) -> Void) {
        BiometricAuthManager.shared.authenticate(reason: "Access your wallet") { success, error in
            if !success {
                completion(.failure(error ?? NSError(domain: "Authentication failed", code: -1)))
                return
            }
            
            guard let privateKey = SecureStorage.shared.loadPrivateKey(identifier: self.walletIdentifier),
                  let wallet = Wallet(privateKey: privateKey) else {
                completion(.failure(NSError(domain: "Failed to load wallet", code: -1)))
                return
            }
            
            self.currentWallet = wallet
            completion(.success(wallet))
        }
    }
    
    func signAndSendTransaction(to: String, amount: Decimal, fee: Decimal, completion: @escaping (Result<String, Error>) -> Void) {
        guard let wallet = currentWallet else {
            completion(.failure(NSError(domain: "No wallet loaded", code: -1)))
            return
        }
        
        BiometricAuthManager.shared.authenticate(reason: "Sign transaction") { success, error in
            if !success {
                completion(.failure(error ?? NSError(domain: "Authentication failed", code: -1)))
                return
            }
            
            var transaction = Transaction(
                from: wallet.address,
                to: to,
                amount: amount,
                fee: fee,
                nonce: Int(Date().timeIntervalSince1970)
            )
            
            guard let signature = wallet.sign(transaction: transaction) else {
                completion(.failure(NSError(domain: "Failed to sign transaction", code: -1)))
                return
            }
            
            transaction.signature = signature
            
            BlockchainAPI.shared.sendTransaction(transaction) { result in
                completion(result)
            }
        }
    }
    
    func getBalance(completion: @escaping (Result<Decimal, Error>) -> Void) {
        guard let wallet = currentWallet else {
            completion(.failure(NSError(domain: "No wallet loaded", code: -1)))
            return
        }
        
        BlockchainAPI.shared.getBalance(address: wallet.address, completion: completion)
    }
}

// MARK: - Data Extensions
extension Data {
    init?(hex: String) {
        let len = hex.count / 2
        var data = Data(capacity: len)
        for i in 0..<len {
            let j = hex.index(hex.startIndex, offsetBy: i*2)
            let k = hex.index(j, offsetBy: 2)
            let bytes = hex[j..<k]
            if var num = UInt8(bytes, radix: 16) {
                data.append(&num, count: 1)
            } else {
                return nil
            }
        }
        self = data
    }
    
    func hexEncodedString() -> String {
        return map { String(format: "%02hhx", $0) }.joined()
    }
    
    func base58Encoded() -> String {
        let alphabet = "123456789ABCDEFGHJKLMNPQRSTUVWXYZabcdefghijkmnopqrstuvwxyz"
        var bytes = [UInt8](self)
        var zerosCount = 0
        
        for byte in bytes {
            if byte != 0 { break }
            zerosCount += 1
        }
        
        bytes = Array(bytes[zerosCount...])
        
        var encoded = ""
        var num = BigInteger(bytes)
        let base = BigInteger(58)
        
        while num > BigInteger(0) {
            let (quotient, remainder) = num.divMod(base)
            let index = alphabet.index(alphabet.startIndex, offsetBy: Int(remainder.value))
            encoded = String(alphabet[index]) + encoded
            num = quotient
        }
        
        for _ in 0..<zerosCount {
            encoded = "1" + encoded
        }
        
        return encoded
    }
}

// MARK: - Simple BigInteger for Base58
struct BigInteger {
    var value: UInt64
    
    init(_ value: UInt64) {
        self.value = value
    }
    
    init(_ bytes: [UInt8]) {
        var val: UInt64 = 0
        for byte in bytes {
            val = val * 256 + UInt64(byte)
        }
        self.value = val
    }
    
    func divMod(_ divisor: BigInteger) -> (quotient: BigInteger, remainder: BigInteger) {
        let q = value / divisor.value
        let r = value % divisor.value
        return (BigInteger(q), BigInteger(r))
    }
    
    static func >(lhs: BigInteger, rhs: BigInteger) -> Bool {
        return lhs.value > rhs.value
    }
}

// MARK: - Main View Controller
class WalletViewController: UIViewController {
    
    private let addressLabel = UILabel()
    private let balanceLabel = UILabel()
    private let sendButton = UIButton(type: .system)
    private let historyButton = UIButton(type: .system)
    private let createWalletButton = UIButton(type: .system)
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Perform security checks
        let securityCheck = SecurityManager.shared.performSecurityChecks()
        if !securityCheck.passed {
            showSecurityAlert(reasons: securityCheck.reasons)
            return
        }
        
        setupUI()
        loadWallet()
    }
    
    private func setupUI() {
        view.backgroundColor = .systemBackground
        title = "Crypto Wallet"
        
        addressLabel.textAlignment = .center
        addressLabel.numberOfLines = 0
        addressLabel.font = .systemFont(ofSize: 12)
        
        balanceLabel.textAlignment = .center
        balanceLabel.font = .systemFont(ofSize: 32, weight: .bold)
        
        sendButton.setTitle("Send", for: .normal)
        sendButton.addTarget(self, action: #selector(sendTapped), for: .touchUpInside)
        
        historyButton.setTitle("History", for: .normal)
        historyButton.addTarget(self, action: #selector(historyTapped), for: .touchUpInside)
        
        createWalletButton.setTitle("Create Wallet", for: .normal)
        createWalletButton.addTarget(self, action: #selector(createWalletTapped), for: .touchUpInside)
        
        let stackView = UIStackView(arrangedSubviews: [
            addressLabel, balanceLabel, sendButton, historyButton, createWalletButton
        ])
        stackView.axis = .vertical
        stackView.spacing = 20
        stackView.translatesAutoresizingMaskIntoConstraints = false
        
        view.addSubview(stackView)
        
        NSLayoutConstraint.activate([
            stackView.centerYAnchor.constraint(equalTo: view.centerYAnchor),
            stackView.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 20),
            stackView.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -20)
        ])
    }
    
    private func showSecurityAlert(reasons: [String]) {
        let alert = UIAlertController(
            title: "Security Warning",
            message: "This app cannot run in an insecure environment:\n\n" + reasons.joined(separator: "\n"),
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Exit", style: .destructive) { _ in
            exit(0)
        })
        present(alert, animated: true)
    }
    
    private func loadWallet() {
        WalletManager.shared.loadWallet { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let wallet):
                    self?.updateUI(wallet: wallet)
                    self?.loadBalance()
                case .failure:
                    self?.showCreateWalletPrompt()
                }
            }
        }
    }
    
    private func updateUI(wallet: Wallet) {
        addressLabel.text = "Address: \(wallet.address)"
        createWalletButton.isHidden = true
    }
    
    private func loadBalance() {
        WalletManager.shared.getBalance { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let balance):
                    self?.balanceLabel.text = "\(balance) BTC"
                case .failure(let error):
                    self?.balanceLabel.text = "Error: \(error.localizedDescription)"
                }
            }
        }
    }
    
    private func showCreateWalletPrompt() {
        let alert = UIAlertController(
            title: "No Wallet Found",
            message: "Would you like to create a new wallet?",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Create", style: .default) { [weak self] _ in
            self?.createWallet()
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    @objc private func createWalletTapped() {
        createWallet()
    }
    
    private func createWallet() {
        WalletManager.shared.createWallet { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let wallet):
                    self?.updateUI(wallet: wallet)
                    self?.loadBalance()
                    self?.showAlert(title: "Success", message: "Wallet created successfully!")
                case .failure(let error):
                    self?.showAlert(title: "Error", message: error.localizedDescription)
                }
            }
        }
    }
    
    @objc private func sendTapped() {
        let alert = UIAlertController(title: "Send Transaction", message: nil, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.placeholder = "Recipient Address"
        }
        alert.addTextField { textField in
            textField.placeholder = "Amount"
            textField.keyboardType = .decimalPad
        }
        alert.addAction(UIAlertAction(title: "Send", style: .default) { [weak self] _ in
            guard let toAddress = alert.textFields?[0].text,
                  let amountString = alert.textFields?[1].text,
                  let amount = Decimal(string: amountString) else {
                return
            }
            self?.sendTransaction(to: toAddress, amount: amount)
        })
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel))
        present(alert, animated: true)
    }
    
    private func sendTransaction(to: String, amount: Decimal) {
        WalletManager.shared.signAndSendTransaction(to: to, amount: amount, fee: 0.0001) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let txHash):
                    self?.showAlert(title: "Success", message: "Transaction sent: \(txHash)")
                    self?.loadBalance()
                case .failure(let error):
                    self?.showAlert(title: "Error", message: error.localizedDescription)
                }
            }
        }
    }
    
    @objc private func historyTapped() {
        showAlert(title: "History", message: "Transaction history feature coming soon")
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

// MARK: - App Delegate
@main
class AppDelegate: UIResponder, UIApplicationDelegate {
    
    var window: UIWindow?
    
    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        
        window = UIWindow(frame: UIScreen.main.bounds)
        let navigationController = UINavigationController(rootViewController: WalletViewController())
        window?.rootViewController = navigationController
        window?.makeKeyAndVisible()
        
        return true
    }
}